@app.route('/predict', methods=['POST'])
def predict_spam():
    try:
        data = request.get_json()
        
        if not data or 'email_text' not in data:
            return jsonify({'error': 'Missing email_text in request'}), 400
        
        email_text = data['email_text']
        
        if not isinstance(email_text, str) or not email_text.strip():
            return jsonify({'error': 'email_text must be a non-empty string'}), 400
        
        email_vector = vectorizer.transform([email_text])
        
        spam_probability = model.predict_proba(email_vector)[0][1]
        
        is_spam = bool(spam_probability > 0.5)
        
        response = {
            'email_text': email_text,
            'spam_probability': float(spam_probability),
            'is_spam': is_spam
        }
        
        return jsonify(response), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy', 'model_loaded': model is not None}), 200

@app.route('/train', methods=['POST'])
def retrain_model():
    try:
        data = request.get_json()
        
        if not data or 'emails' not in data:
            return jsonify({'error': 'Missing emails in request'}), 400
        
        emails = data['emails']
        
        if not isinstance(emails, list) or len(emails) == 0:
            return jsonify({'error': 'emails must be a non-empty list'}), 400
        
        texts = []
        labels = []
        
        for email in emails:
            if 'text' not in email or 'label' not in email:
                return jsonify({'error': 'Each email must have text and label fields'}), 400
            texts.append(email['text'])
            labels.append(email['label'])
        
        global vectorizer, model
        
        vectorizer = CountVectorizer(max_features=100, stop_words='english')
        X = vectorizer.fit_transform(texts)
        y = np.array(labels)
        
        model = LogisticRegression(random_state=42, max_iter=1000)
        model.fit(X, y)
        
        with open(model_path, 'wb') as f:
            pickle.dump(model, f)
        
        with open(vectorizer_path, 'wb') as f:
            pickle.dump(vectorizer, f)
        
        return jsonify({'message': 'Model retrained successfully', 'samples': len(texts)}), 200
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

